#[derive(Clone, Copy)]
pub struct LinkedList&lt;'a, T&gt; {
 next: Option&lt;&amp;'a Self&gt;,
 value: T,
}

const A: LinkedList&lt;u32&gt; = LinkedList {
 next: None,
 value: 42,
};

const B1: LinkedList&lt;u32&gt; = LinkedList {
 next: Some(&amp;A),
 value: 13,
};

const B2: LinkedList&lt;u32&gt; = LinkedList {
 next: Some(&amp;A),
 value: 0,
};

#[no_mangle]
fn peek() -&gt; LinkedList&lt;'static, u32&gt; {
 B2
}

